#!/bin/bash
# HERCOSSNUX NPU - Fase A, Paso 18 (Layer 5): bring-up en silicio.
#
# Instala el binario de validacion en placa y su generador de datos.
#
# npu_run.c hace:
#   1. mmap de /dev/mem sobre los registros (0x80000000) y el buffer DDR
#      (0x70000000, 16 MB, no-map)
#   2. comprueba el registro ID (0x4E505531) para verificar que el PDI
#      cargado es el correcto
#   3. escribe pesos e imagenes en DDR
#   4. dispara load_weights y espera done
#   5. por cada imagen: escribe, dispara start, espera done, lee la clase
#   6. acumula la firma FNV y la compara con 0x6084FD2A
#
# CUIDADO CON no-map: glibc aarch64 usa DC ZVA y stp de 128 bits en memset
# y memcpy, que fallan con SIGBUS sobre memoria no mapeada por el kernel.
# Todos los accesos al buffer son bucles byte a byte sobre punteros
# volatile. No introducir memcpy/memset en esas rutas.
#
# CRITERIO: SIG_CLASE = 0x6084FD2A, la misma firma que dan el oraculo
# Python, la simulacion del nucleo y la integracion AXI. Si el silicio la
# reproduce, la cadena de verificacion queda cerrada de extremo a extremo.
#
# Requiere: aarch64-linux-gnu-gcc, y los Pasos 1-14 para los datos.
(
set -e
DIR="$HOME/vhdl_repo/IP_Cores/NPU"
if [ ! -f "$DIR/oracle/oracle_npu.py" ]; then
  echo "FALLO: falta oracle/oracle_npu.py (corre primero los Pasos 1-14)"; exit 1
fi
mkdir -p "$DIR/silicio"
base64 -d << "EOF" > "$DIR/silicio/npu_run.c"

EOF
base64 -d << "EOF" > "$DIR/silicio/gen_bin.py"

EOF
base64 -d << "EOF" > "$DIR/silicio/build_npu_run.sh"

EOF
chmod +x "$DIR/silicio/build_npu_run.sh"
cd "$DIR"
bash silicio/build_npu_run.sh
)
